module RefModule(
    X    ,
    A    ,
    SLEEP
);// Module ports
    output X    ;
    input  A    ;
    input  SLEEP;

    // Module supplies
    supply1 KAPWR;
    supply0 VGND ;
    supply1 VPB  ;
    supply0 VNB  ;

    // Local signals
    wire obf_sleepn;

    //  Name  Output  Other arguments
    not not0 (obf_sleepn, SLEEP          );
    and and0 (X     , A, obf_sleepn      );

endmodule
